// 通用柯里化工具函数（原实现无问题，保留）
function curry(fn) {
  return function curried(...args) {
    if (args.length >= fn.length) {
      return fn.apply(this, args);
    } else {
      return function(...nextArgs) {
        return curried.apply(this, args.concat(nextArgs));
      }
    }
  };
}

// 修正1：柯里化构造器增加显式类型标识，避免隐式判断
const curryRule = curry((threshold, discountValue, isPercent = false) => (amount) => {
  if (amount >= threshold) {
    // 显式区分比例/满减逻辑，不再依赖折扣值大小判断
    return isPercent ? amount * discountValue : amount - discountValue;
  }
  return amount;
});

// 修正2：高阶函数改为从左到右应用规则，符合业务要求
function composeDiscounts(...rules) {
  return function(amount) {
    // 从左到右遍历，第一个规则最先执行
    return rules.reduce((acc, rule) => rule(acc), amount);
  };
}

// 预定义规则实例：比例折扣显式传入true标识
const reduce100 = curryRule(100, 10); // 满减，默认isPercent=false
const reduce200 = curryRule(200, 30); // 满减
const memberDiscount = curryRule(0, 0.9, true); // 比例折扣
const newUserDiscount = curryRule(0, 0.95, true); // 比例折扣

// 通用折扣管道：传入顺序为先满减（阈值从高到低）后比例，符合业务优先级
const discountPipeline = composeDiscounts(reduce200, reduce100, memberDiscount, newUserDiscount);
```
---
### 最终结论
当前实现**错误**，核心问题为：
1. 柯里化层面：`curryRule`通过折扣值大小隐式判断规则类型，导致小额满减规则被误判为比例折扣；
2. 高阶函数层面：`composeDiscounts`使用`reduceRight`导致规则应用顺序从右到左，违反业务要求的从左到右执行顺序，进而导致满减/比例优先级颠倒、同类型规则阈值顺序错误。
修正后代码通过显式类型标识解决规则判断错误，通过`reduce`实现从左到右的组合顺序，完全满足业务约束：柯里化支持分步传递参数生成规则函数，高阶函数保证传入顺序即为执行顺序，配合规则传入时先满减（阈值从高到低）后比例的排序，完全对齐业务优先级要求。

